INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('geral', 'É normal bebê chorar muito depois da vacina?', 'Que angústia, mãe! 😭 Ver o bebê desconfortável dá uma dor no coração. Saiba que cólica é super comum e passa. Para aliviar agora: - Observe o padrão e anote quando acontece - Converse com seu pediatra sobre o que você notou - Confie no seu instinto de mãe Mas atenção: se a barriga ficar muito dura, se vomitar verde ou se o bebê não conseguir mamar, procure o pediatra.', 'geral', 'geral', 'geral', 0, 'true');
